LAYER
	NAME "sectores"
	GROUP "COFOPRI"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	HEADER "plantillas/inicio.html"
	TEMPLATE "plantillas/allpa/cofopri/sectores.html"
	FOOTER "plantillas/fin.html"
	STATUS on
	DATA "geom FROM (SELECT gid, id_dist, cod_sector, id_sector, geom FROM cofopri.sectores) as allpa using unique gid using srid=4326"
	INCLUDE "configuracion/postgresql_allpa.map"
	PROJECTION
		"init=epsg:4326"
	END
	CLASSITEM "gid"
	METADATA
		"wms_group_title" "COFOPRI"
		"queryable" "true"
		"wms_metadataurl_href" "LUISAMOS"
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Sectores"
		"wms_abstract" "Sectores || Organismo de Formalización de la Propiedad Informal - COFOPRI :: Perú"
		"wms_credit" "COFOPRI"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_extent" "-81.306784 -17.20814673 -69.084859109 -3.49278267400001"
		"wms_srs" "EPSG:4326"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
		"wms_enable_request" "*"
	END
	CLASS
		NAME "Sectores"
		EXPRESSION /./
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 255 255 0
			WIDTH 1
		END
	END
END # Layer